const Q_PHYSICS_2008=[{"id": "objective>Physics>2008>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The dimensions of electromotive force are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>LT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Electromotive force, E <br/> Recall: Electrical Energy, E = IVt <br/> Recall: the dimension of energy is = ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> (From Force × displacement) <br/> ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> = I × V × T <br/> V = = ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. <br/> NOTE: V (voltage) has the same dimension as electromotive force, E.</div>", "topic": "MEASUREMENTS AND UNITS : DIMENSIONS"}, {"id": "objective>Physics>2008>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Force(N)  <br/>  II. Torque (Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>)  <br/>  III. Current (A)  <br/>  IV. Power (W) <br/> Which of the above are the correct S. I.Units of the quantities indicated?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and II only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV only</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The S.I unit of force is Newton (N) <br/> The S.I unit of torque is Newton-metre (Nm) <br/> The S.I unit of current is Ampere (A) <br/> The S.I unit of power is Watt (W)</div>", "topic": "MEASUREMENTS AND UNITS : DERIVED PHYSICAL QUANTITIES AND THEIR UNITS~~MEASUREMENTS AND UNITS : FUNDAMENTAL PHYSICAL QUANTITIES"}, {"id": "objective>Physics>2008>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The resultant of two forces 12N and 5N is 13N. What is the angle between the two <br/> forces?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0 ° </div>", "<div style=\"font-family:Cambria;font-size:17px;\">45 ° </div>", "<div style=\"font-family:Cambria;font-size:17px;\">90 ° </div>", "<div style=\"font-family:Cambria;font-size:17px;\">180 °</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The angle between the two forces is 90°, i.e they are perpendicular to each other. <br/>  <img src=\"2008/img3a.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "EQUILIBRIUM OF FORCES : EQUILIBRIUM OF PARTICLES"}, {"id": "objective>Physics>2008>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is NOT a vector quantity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Altitude </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Acceleration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Displacement </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Weight</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Altitude, i.e, height is not a vector quantity. vectors quantities have both magnitude and direction , while scalar quantity has only magnitude , altitude does not have direction , hence its a scalar quantity </div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2008>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A force F is required to keep a 5kg mass moving round a cycle of radius 3.5m at a speed of 7ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. What is the speed, if the force is tripled?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.0ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.6ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.1ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">21.0ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mv<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />r</td><td style=\"text-align:center;\">--------------</td><td style=\"text-align:center;\">(i)</td></tr></table></div> <br/> keep m and r constant <br/> F α V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 3F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> (the force is tripled) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />49</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 147 <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">147&nbsp;</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 7&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span> = 12.1ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2008>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a wheel 1.2m in a diameter rotates at one revolution per second, calculate the velocity of the wheel.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.6ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.8ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.5ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Diameter, d = 1.2m, radius, r = 0.6m <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">angular</td><td style=\"text-align:center;\">displacement,</td><td style=\"text-align:center;\">θ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1</td><td style=\"text-align:center;\">revolution</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">360°</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2π</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2(</td><td style=\"text-align:center;\">22<hr size=\"1\" />7</td><td style=\"text-align:center;\">)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">44<hr size=\"1\" />7</td></tr></table></div> <br/> time, t = 1s <br/> Velocity, V = unknown <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">Velocity,</td><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">s<hr size=\"1\" />t</td><td style=\"text-align:center;\">--------</td><td style=\"text-align:center;\">(i)</td></tr></table></div> <br/> s = θr -------------- (ii) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">θr<hr size=\"1\" />t</td></tr></table></div> <br/> V = 44/7 × 0.6 = 3.77ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> V = 3.8ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2008>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body of mass 4kg resting on a smooth horizontal plane is simultaneously acted upon by two perpendicular forces 6N and 8N. Calculate the acceleration of the <br/> motion.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.5ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.5ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically, <br/> <img src=\"2008/img7.png\" style=\"position:relative;max-width:100%;\"/>  <br/> <img src=\"2008/img8.png\" style=\"position:relative;max-width:100%;\"/> <br/> R<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 8<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 6<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> R<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 64 + 36 <br/> R<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 100 <br/> R = 10N <br/> Net force on the 4kg body = 10N <br/> From Newton's Second Law of motion <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">N</span> = ma <br/> 10 = 4a <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.5ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></td></tr></table></div> </div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES~~MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2008>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The diagram above shows a plank RS pivoted at its centre of gravity O and is in equilibrium with the weights P and Q. If a weight 2P is added to P, the plank will be in equilibrium again by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">moving Q nearer to O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">moving P nearer to O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adding a weight Q to O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">moving P further away from O.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If a weight 2P is added to P, the equilibruim will be disturbed, i.e, the plank will bend to the left; and in order to balance the plank, the mass P is moved nearer to O.</div>", "topic": "EQUILIBRIUM OF FORCES : CENTRE OF GRAVITY AND STABILITY"}, {"id": "objective>Physics>2008>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. All the three forces must be concurrent.  <br/>  II. The upward force is equal to the downward force.  <br/>  III. The algebraic sum of the moment about any point must be zero. Which of the above conditions must hold for a body acted upon by a system of three coplanar forces in equilibrium?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and II only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct conditions for a body acted upon by a system of three coplanar forces in equilibrium are: <br/>  <br/> II. The algebraic sum of the upward force is equal to the downward force (and similarly for horizontal forces). This ensures there is no net force acting on the body in any direction. <br/> III. The algebraic sum of the moments of all the forces about any point must be zero. This ensures the body is not rotating. <br/> I. All the three forces must be concurrent (acting at the same point) is NOT required. Even if the forces are not acting at the same point, as long as the net force and net moment conditions are met, the body can be in equilibrium. <br/>  <br/> Therefore, the correct answer is II and III only.</div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>2008>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the frequency of vibration if the balance wheel of a wristwatch makes 90 revolutions in 25s?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.01Hz </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.04Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.27Hz </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.60Hz</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> number of revolutions, n = 90 <br/> time, t = 25s <br/> Frequency, F = unknown <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">n<hr size=\"1\" />t</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">90<hr size=\"1\" />25</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3.6Hz</td></tr></table></div></div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>2008>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a body of mass 5kg is thrown vertically upwards with velocity u, at what height will the potential energy equal to the kinetic energy?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">h = U<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">h = U<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/4g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">h = 2U<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">h = U<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/2g</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> The mass, m of the body = 5kg <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">K.E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">mu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> P.E = mgh <br/> when K.E = P.E <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">mu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mgh</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">gh</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">h</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />2g</td></tr></table></div></div>", "topic": "WORK ENERGY AND POWER : CONSERVATION OF ENERGY"}, {"id": "objective>Physics>2008>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Counting of currency notes with moist fingers is based on the principles of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diffusion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cohesion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adhesion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">viscosity</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The principle that allows us to count currency notes with moist fingers is adhesion. Adhesion is the tendency of dissimilar particles or surfaces to cling to one another. When we moisten our fingers, the water on our fingers adheres to the surface of the currency note, allowing us to pick up one note at a time. Therefore, the correct answer is adhesion which corresponds to option 3.</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : MOLECULAR NATURE OF MATTER"}, {"id": "objective>Physics>2008>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A motorcycle of mass 100kg moves round in a circle of radius 10m with a velocity of 5ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. Find the coefficient of friction between the road and the tyres.[g = 10m/s]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25.00 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.50 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.25 </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Mass, m = 100kg <br/> velocity, v = 5ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, radius, r = 10m <br/> co-efficient of friction = unknown <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">μ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<hr size=\"1\" />R</td><td style=\"text-align:center;\">---------</td><td style=\"text-align:center;\">*</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Also</td><td style=\"text-align:center;\">recall:</td><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mv<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />r</td><td style=\"text-align:center;\">---------------------</td><td style=\"text-align:center;\">*</td><td style=\"text-align:center;\">*</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100(5<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>)<hr size=\"1\" />10</td></tr></table></div> <br/> F = 10(5<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>) = 10(25) = 250N <br/> R = mg -------------- * * * <br/> R = 100 × 10 = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>N <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">μ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">250<hr size=\"1\" />10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.25</td></tr></table></div></div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2008>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The efficiency of the pulley system shown above is 80%. Find the effort E required to lift a load of 1200N.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">275N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">325N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">375N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">573N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Efficiency, E = 80% <br/> Load, L = 1200N <br/> Effort, E = unknown <br/> Recall: <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Efficiency</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">M.A<hr size=\"1\" />V.R</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td><td style=\"text-align:center;\">-----------------</td><td style=\"text-align:center;\">(i)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">M.A</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">L<hr size=\"1\" />E</td><td style=\"text-align:center;\">--------------</td><td style=\"text-align:center;\">(ii)</td></tr></table></div> <br/> V.R = Number of pulleys (in this case) ------------ (iii) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">80</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1200/E<hr size=\"1\" />4</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">320</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1200<hr size=\"1\" />E</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">120,000<hr size=\"1\" />320</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12000<hr size=\"1\" />32</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1500<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">375N</td></tr></table></div></div>", "topic": "SIMPLE MACHINES : EFFICIENCY OF MACHINES"}, {"id": "objective>Physics>2008>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A spring of force constant 500Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> is compressed such that its length shortens by 5cm. The energy stored in the spring is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.625J </div>", "<div style=\"font-family:Cambria;font-size:17px;\">6,250J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">62,500J </div>", "<div style=\"font-family:Cambria;font-size:17px;\">625,000J</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given, <br/> Force constant, K = 500Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Compression, e = 5cm = 0.05m <br/> Energy stored, E = unknown <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">Energy</td><td style=\"text-align:center;\">stored</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">spring</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">ke<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">500</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">(0.05)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">250×25<hr size=\"1\" />10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6250<hr size=\"1\" />10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.625J</td></tr></table></div></div>", "topic": "ELASTICITY : WORK DONE IN SPRINGS AND ELASTIC STRINGS"}, {"id": "objective>Physics>2008>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the Hare's apparatus, water rises to a height of 26.5cm in one limb. If a liquid rises to a height of 20.4cm in the other limb, what is the relative density of the liquid?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.8 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.1 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.2 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.3</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Hare's apparatus, <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td></tr></table></div> <br/> D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> (26.5)(1) = D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> × 20.4 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">26.5<hr size=\"1\" />20.4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.299</td></tr></table></div> <br/> D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 1.3gcm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> Relative density = 1.3</div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>2008>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When cold water is poured on a can containing hot water, the can collapses because the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">steam condenses and occupies the partial vacuum in the can</div>", "<div style=\"font-family:Cambria;font-size:17px;\">external air pressure counterbalances the pressure within the can</div>", "<div style=\"font-family:Cambria;font-size:17px;\">steam expands to occupy the vacuum remaining in the can</div>", "<div style=\"font-family:Cambria;font-size:17px;\">external pressure becomes greater than the pressure within the can</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When cold water is pound on a can containing hot water, the can collapses because the external pressure becomes greater than the pressure within the can.</div>", "topic": "PRESSURE"}, {"id": "objective>Physics>2008>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An empty density bottle weighs 2N. If it weighs 5N when filled with water and 4N when filled with olive oil, the relative density of olive oil is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1/3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2/3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2/5</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Weight of bottle, W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">b</span> = 2.0N <br/> Weight of water, W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">w</span> = 3.0N <br/> Weight of oil, W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> = 2.0N <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R.D</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Weight of substance<hr size=\"1\" />Weight of equal volume of water</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R.D</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.67</td></tr></table></div></div>", "topic": "LIQUIDS AT REST : RELATIVE DENSITY"}, {"id": "objective>Physics>2008>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The thermometric property of a thermocouple is the change in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">equivalent resistance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electromotive force</div>", "<div style=\"font-family:Cambria;font-size:17px;\">colour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pressure.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A thermocouple is a device that measures temperature by the use of two different metals that produce a voltage (an electromotive force) that is temperature dependent. Therefore, the thermometric property of a thermocouple is the change in electromotive force.</div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>2008>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During summer, the balance wheel of a clock expands. What effect does this have on the accuracy of the clock?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The clock gains time.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The accuracy of the clock is not affected.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The clock loses time.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The clock stops working.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During summer, the balance wheel of a clock expands and the clock begins to function slowly, i.e, it loses time.</div>", "topic": "THERMAL EXPANSION : SOLIDS"}, {"id": "objective>Physics>2008>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A sealed flask contains 600cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of air at 27 ° C and is heated to 35 ° C at constant pressure. The new volume is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">508cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">516cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">608cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">616cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Initial temperature, T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 27°C = 300K <br/> Initial volume, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 600cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Final temperature, T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 35°C = 308K <br/> Final volume, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = Unknown <br/> N.B: Pressure is constant <br/> In this case, we apply Charles Law <br/> V α T <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">600<hr size=\"1\" />300</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />308</td></tr></table></div> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 308 × 2 = 616cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2008>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A block of aluminium is heated electrically by a 25W heater. If the temperature rises by 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C in 5 minutes, the heat capacity of the aluminium is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">850JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">750JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">650JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">500JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Power, P = 25W <br/> Temperature change, Δθ = 10°C <br/> time, t = 5 minutes = 5(60) = 300s <br/> Heat capacity, H = unknown <br/> Recall: Q = HΔθ <br/> Electrical energy in this case <br/> P × t = HΔθ <br/> 25 × 300 = H × 10 <br/> H = 750Jk<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2008>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The diagram above is the heating curve of a solid. QR is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">melting region</div>", "<div style=\"font-family:Cambria;font-size:17px;\">boiling region</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sublimation region</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporating process</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Point QR is the melting point where solids turn to liquids.</div>", "topic": "CHANGE OF STATE : MELTING"}, {"id": "objective>Physics>2008>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the partial pressure of water vapour at 27 ° C is 18mm Hg and the saturated vapour pressure of the atmosphere at the same temperature is 24mm Hg, the relative humidity at this temperature is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">33%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">75% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">82%</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given <br/> Temperature, T = 25°C <br/> Partial Pressure = 18mmHg <br/> SVP = 24 mmHg <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R.H</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">18<hr size=\"1\" />24</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">75%</td></tr></table></div></div>", "topic": "VAPOURS : DEW POINT, HUMIDITY AND RELATIVE HUMIDITY"}, {"id": "objective>Physics>2008>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a good thermos flask, the main cause of heat loss is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">conduction through the cork</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the plastic base of the thermos flask</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the silvered walls and shiny metals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the outer cover or jacket.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main cause of heat loss in a thermos flask is due to: <br/>  <br/> Conduction through the cork <br/>  <br/> Here's why the other options are incorrect: <br/>  <br/> <span style=\"font-weight:bold;\"> The plastic base of the thermos flask: </span> The plastic base is often designed to be a poor conductor to minimize heat loss. <br/> <span style=\"font-weight:bold;\"> The silvered walls and shiny metals: </span> These reflective surfaces actually help prevent heat loss by radiation. <br/> <span style=\"font-weight:bold;\"> The outer cover or jacket: </span> The outer cover provides additional insulation but isn't the main culprit for heat loss. <br/>  <br/> Conduction is the transfer of heat through direct contact between objects. The cork, while providing a good seal, is still a material that can conduct heat to some extent. This is why a good quality thermos flask will have a thick or low-conductivity cork to minimize heat loss through conduction.</div>", "topic": "HEAT TRANSFER : THERMOS FLASK"}, {"id": "objective>Physics>2008>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given the progressive wave equation y = 5 sin (2000πt – 0.4x), calculate the wavelength.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">12.4m </div>", "<div style=\"font-family:Cambria;font-size:17px;\">15.7m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">17.5m </div>", "<div style=\"font-family:Cambria;font-size:17px;\">18.6m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> y = 5sin(2000πt - 0.4x) ----------------- (i) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">0.4x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2π<hr size=\"1\" />λ</td><td style=\"text-align:center;\">x</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">0.4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2π<hr size=\"1\" />λ</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2π<hr size=\"1\" />0.4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5π</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5(3.142)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">15.7m</td></tr></table></div></div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2008>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The above figure shows the motion of a progressive wave along a string. The particle motion of the medium is in the direction</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">parallel to OX</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parallel to OY</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> to OX</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> to OY.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Particle motion of a string (transverse wave) is parallel to OY (or perpendicular to OX)</div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2008>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The fundamental property of a propagating wave which depends only on the source and not the medium of propagation is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wavelength </div>", "<div style=\"font-family:Cambria;font-size:17px;\">harmonics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">frequency </div>", "<div style=\"font-family:Cambria;font-size:17px;\">velocity.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The frequency of a wave is determined by the source of the wave, not the medium through which it travels. Frequency is the number of complete wave cycles that pass a given point in a second. It is measured in Hertz (Hz).</div>", "topic": "CHARACTERISTICS OF SOUND WAVES : OVERTONES PRODUCED BY VIBRATING STRINGS AND THEIR COLUMNS"}, {"id": "objective>Physics>2008>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the length of a vibrating string is reduced by one-third, its frequency <br/> becomes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">three times its former value</div>", "<div style=\"font-family:Cambria;font-size:17px;\">twice its former value</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one-third of its former value</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one-sixth of its former value.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">1<hr size=\"1\" />L</td></tr></table></div> <br/> When the length of a vibrating string is reduced by one-third, its frequency becomes three times its former value.</div>", "topic": "CHARACTERISTICS OF SOUND WAVES : OVERTONES PRODUCED BY VIBRATING STRINGS AND THEIR COLUMNS"}, {"id": "objective>Physics>2008>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Total internal reflection of light  <br/>  II. Conservation of light energy  <br/>  III. Relative motion of the earth, sun and moon.  <br/> IV. Rectilinear propagation of light.  <br/>  Which of the above is a phenomenon of total solar eclipse?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III and IV only.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A total solar eclipse is a phenomenon that occurs when the moon passes between the sun and the earth, blocking the sun's light. This involves the relative motion of the earth, sun, and moon (III) and the rectilinear propagation of light (IV). Rectilinear propagation of light is the principle that light travels in straight lines.</div>", "topic": "LIGHT ENERGY : PROPAGATION OF LIGHT"}, {"id": "objective>Physics>2008>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object of height 4cm is placed in front of a cuboid pinhole camera of size 6cm. If the image formed is 2cm high, how far is the object from the pinhole?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.0cm </div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.0cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.0cm </div>", "<div style=\"font-family:Cambria;font-size:17px;\">16.0cm</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Object height, H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> = 4cm <br/> Size of pin hole camera = 6cm = image distance (v) <br/> Image height, H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span> = 2cm <br/> Object distance, U = ? <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">Magnification</td><td style=\"text-align:center;\">(m)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<hr size=\"1\" />U</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span><hr size=\"1\" />H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">6<hr size=\"1\" />U</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />4</td></tr></table></div> <br/> 2U = 24 <br/> U = 12cm</div>", "topic": "LIGHT ENERGY : PROPAGATION OF LIGHT"}, {"id": "objective>Physics>2008>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object of height 5cm is placed at 20cm from a concave  mirror focal lenght <br/> 10cm. The image height is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20cm </div>", "<div style=\"font-family:Cambria;font-size:17px;\">15cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10cm </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5cm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given, <br/> Object height, H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> = 5cm <br/> Object distance, u = 20cm <br/> focal length, f = 10cm <br/> image height, H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span> = unknown <br/> Recall:<div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">1<hr size=\"1\" />f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />20</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />10</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1<hr size=\"1\" />20</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2 - 1<hr size=\"1\" />20</td></tr></table></div> <br/> 20 = v, v = 20cm <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span><hr size=\"1\" />H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />u</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">5<hr size=\"1\" />H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20<hr size=\"1\" />20</td></tr></table></div> <br/> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span> = 5cm</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES : USE OF THE MIRROR FORMULA"}, {"id": "objective>Physics>2008>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Convex mirrors are used as driving mirrors because images formed are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">erect, virtual and diminished</div>", "<div style=\"font-family:Cambria;font-size:17px;\">erect, real and diminished</div>", "<div style=\"font-family:Cambria;font-size:17px;\">erect, virtual and magnified</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inverted, virtual and diminished.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Convex mirrors are used as driving mirrors because the image formed are virtual, erect and diminished.</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES"}, {"id": "objective>Physics>2008>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a convex lens of focal length 12cm is used to produce a real image four times <br/> the size of the object, how far from the lens must the object be placed?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10cm </div>", "<div style=\"font-family:Cambria;font-size:17px;\">15cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20cm </div>", "<div style=\"font-family:Cambria;font-size:17px;\">25cm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Focal length, f = 12cm <br/> v = 4u <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">magnification</td><td style=\"text-align:center;\">(m)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />u</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4</td></tr></table></div> <br/> object distance, u = unknown <br/> Recall:  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />f</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />12</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />12</td></tr></table></div> <br/> v = 60cm <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">60<hr size=\"1\" />u</td></tr></table></div> <br/> u = 15cm</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2008>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object placed at the bottom of a well full of clear water appears closer to the <br/> surface due to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diffraction </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reflection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refraction </div>", "<div style=\"font-family:Cambria;font-size:17px;\">polarization</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An object placed at the bottom of a wall full of clear water appears closer to the surface due to refraction.</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2008>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the microscope, the eyepiece lens merely acts as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an inverter </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a refiner</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a diminisher </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a magnifier</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> The basic functions of a microscope is to magnify <br/>  <br/> First, the purpose of a microscope is to magnify a small object or to magnify the fine details of a larger object in order to examine minute specimens that cannot be seen by the naked eye.</div>", "topic": "OPTICAL INSTRUMENTS"}, {"id": "objective>Physics>2008>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An observer with normal eyes views an object with a magnifying glass of focal <br/> length 5cm. The angular magnification is ...... [least distance of distinct vision D = 25cm]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">-6 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">-5 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">6</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">M = 1 +<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\"> 25cm</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">F</span> <br/>  = 1 + <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">25</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">5</span> <br/> M = 1 + 5 <br/> = 6</div>", "topic": "OPTICAL INSTRUMENTS : ANGULAR MAGNIFICATION"}, {"id": "objective>Physics>2008>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A short chain is sometimes attached to the back of a petrol tanker to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">generate more friction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure the balancing of the tanker</div>", "<div style=\"font-family:Cambria;font-size:17px;\">caution the driver when overspeeding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conduct excess charges to the earth</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A short chain is sometimes attached to the back of petrol tanker to conduct excess charges to the earth.</div>", "topic": "ELECTROSTATICS"}, {"id": "objective>Physics>2008>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  Find the effective resistance in the diagram above.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6Ω </div>", "<div style=\"font-family:Cambria;font-size:17px;\">12Ω </div>", "<div style=\"font-family:Cambria;font-size:17px;\">16Ω </div>", "<div style=\"font-family:Cambria;font-size:17px;\">24Ω</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given the diagram <br/> <img src=\"2008/img39.png\" style=\"position:relative;max-width:100%;\"/> <br/> From the diagram given, the same current will flow across the resistors, hence, they are in series. <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = 4 + 4 + 4 + 4 + 4 + 4 = 24Ω </div>", "topic": "CURRENT ELECTRICITY : RESISTANCE IN SERIES AND IN PARALLEL"}, {"id": "objective>Physics>2008>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electric generator has an e.m.f. of 240V and an internal resistance of 1Ω. If the current supplied by the generator is 20A when the terminal voltage is 220V, <br/> find the ratio of the power supplied to the power dissipated.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">11:1 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:11</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12:11 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">11:12</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> E.m.f, E = 240V <br/> Internal resistance, r = 1.0 ohms <br/> Current, I = 20A <br/> Terminal P.d, V = 220V <br/> N.B: E = V + Ir <br/> P = IV (dissipated) <br/> P = IE (supplied) <br/> Power dissipated, P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">d</span> = 20 × 220 = 4400W <br/> Power supplied, P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> = 20 × 240 = 4800W <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span><hr size=\"1\" />P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">d</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4800<hr size=\"1\" />4400</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12<hr size=\"1\" />11</td></tr></table></div> <br/> </div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2008>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A generator is on daily use and in the process, ten 60W and five 40W tungsten <br/> bulbs are on for the same time interval. The energy consumed daily is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.96kWh </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.92kWh</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.60kWh </div>", "<div style=\"font-family:Cambria;font-size:17px;\">19.20kWh</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ten 60W = 60 x 10 = 600W  <br/>  five 40W = 5 x 40 = 200W  <br/>  Total power consumed in KW = 0.2+0.6 =0.8kW in 24hrs, total power = 0.8 x 24 = 19.2kWh.</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2008>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The d.c. generator has essentially the same components as the a.c. generator except the presence of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">slip-ring </div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon brushes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">split ring </div>", "<div style=\"font-family:Cambria;font-size:17px;\">armature</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main difference between a DC generator and an AC generator is the method of collecting the current produced in the armature. In a DC generator, a split ring (also known as a commutator) is used to collect the current and ensure that the current always flows in the same direction. In an AC generator, slip rings are used to collect the current, allowing the current to change direction with each rotation of the armature.</div>", "topic": "ELECTROMAGNETIC INDUCTION : A.C. AND D.C GENERATORS"}, {"id": "objective>Physics>2008>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A step-down transformer has a power output of 50W and efficiency of 80%. If the mains supply voltage is 200V, calculate the value of the primary current of the transformer.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.31A </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.20A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.40A </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.00A</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The output of the transformer = 50W. This is 80% of the input  <br/>  Hence, the value of the input = 100/80 x 50W = 62.5W  <br/>  Power from the mains =IV  <br/>  I = 62.5/200 = 0.31A.</div>", "topic": "ELECTROMAGNETIC INDUCTION : TRANSFORMERS"}, {"id": "objective>Physics>2008>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  Given three inductors of inductances 5mH, 10mH and 20mH connected in series, the effective inductance is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.35mH </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.50mH </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.90mH </div>", "<div style=\"font-family:Cambria;font-size:17px;\">35.00mH</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since the inductors are connected in series, <br/>  <br/> The effective inductance = 5mH + 10mH + 20mH = 35mH.</div>", "topic": "SIMPLE A. C. CIRCUITS : INDUCTOR - INDUCTIVE REACTANCE"}, {"id": "objective>Physics>2008>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If electrons are accelerated from rest through a potential difference of 10kV, <br/> what is the wavelength of the associated electron?  <br/> [m = 9.1 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-31</span>kg, e = 1.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>C, h = 6.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>Js]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.22 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span>m </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.87 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span>m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.27 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">11</span>m </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.27 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span>m</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the equation eV=hc/λ e = charge, V= potential difference, C= speed of light and λ = wavelength λ = hc/eV  <br/>  Hence, λ = 6.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>x 3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>÷(1.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>x10,000) λ = 1.24 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span>m.</div>", "topic": "ELEMENTARY MODERN PHYSICS : EINSTEIN’S EQUATION AND STOPPING POTENTIAL"}, {"id": "objective>Physics>2008>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>N + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>He → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">17</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O + X.  <br/>  In the equation above, the particle X is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a proton </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a neutron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an α-particle </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a β-particle</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">14 + 4 = 17 + x <br/> x = 18 - 17 <br/> x = 1 <br/> soling the subscript  <br/>  7 + 2 = 8 + x <br/> x = 9 - 8 <br/> x = 1 <br/> Hence X is roton <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>X</div>", "topic": "ELEMENTARY MODERN PHYSICS : RADIOACTIVITY"}, {"id": "objective>Physics>2008>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Caesium has a work function of 3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>J. The maximum energy of liberated <br/> electrons when it is illuminated by light of frequency 6.7 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span>Hz is <br/> [h = 6.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-35</span>Js] <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.42 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>J </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.00 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.42 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>J </div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.42 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>J <br/> </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Max kinetic energy, K.E = hf - W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>, where, W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> = work function  <br/>  h = planck constant, f = frequency  <br/>  W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>= 3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>J, hf = 6.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-35</span>x 6.7 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span> = 4.42 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>  <br/>  K.E = 4.42 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span> - 3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>= 1.42 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>J.</div>", "topic": "ELEMENTARY MODERN PHYSICS : THERMIONIC AND PHOTOELECTRIC EMISSIONS"}, {"id": "objective>Physics>2008>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Zener diode is used for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">current amplification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">power amplification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">voltage regulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">energy conversion.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Voltage regulation, Zener diode is used for voltage regulation limits the current through the diode and drops the excess voltage when the diode is conducting Zener diode helps to keep the voltage of a power supply steady <br/> </div>", "topic": "INTRODUCTORY ELECTRONICS : DIODES"}, {"id": "objective>Physics>2008>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a pure semiconductor is heated, its resistance</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remains the same</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases and then decreases.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The resistance of semiconductors decreases with a rise in temperature while that of metals increases with a temperature rise.</div>", "topic": "INTRODUCTORY ELECTRONICS"}, {"id": "objective>Physics>2008>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. For current amplification  <br/> II. For voltage stabilization  <br/>  III. For power amplification  <br/> IV. As a switch.  <br/> Which of the above are the uses of a transistor?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II, III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and IV only.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A transistor is a semiconductor device used to amplify or switch electronic signals and electrical power. It is composed of semiconductor material usually with at least three terminals for connection to an external circuit. The uses of a transistor include current amplification, power amplification, and as a switch. However, it is not typically used for voltage stabilization. Hence, the correct answer is 'I, III and IV only'.</div>", "topic": "INTRODUCTORY ELECTRONICS : TRANSISTORS"}];
